import React from "react";
import L from "leaflet";
import { Marker, Popup } from "react-leaflet";

const issIcon = L.divIcon({
  className: "",
  html: "<div style='font-size:28px;line-height:1;filter:drop-shadow(0 0 6px rgba(122,245,255,.7));'>🛰</div>",
  iconSize: [28, 28],
  iconAnchor: [14, 14],
  popupAnchor: [0, -14],
});

export default function IssMarker({ position }) {
  if (!position) {
    return null;
  }

  return (
    <Marker position={[position.latitude, position.longitude]} icon={issIcon}>
      <Popup>International Space Station</Popup>
    </Marker>
  );
}
